1	package service
2	
3	import (
4		"context"
5		"crypto/rand"
6		"encoding/base64"
7		"errors"
8		"fmt"
9		"log/slog"
10		"math/big"
11		"strings"
12		"time"
13	
14		"github.com/google/uuid"
15		"golang.org/x/crypto/bcrypt"
16	
17		"github.com/harborworks/booking-hub/internal/domain"
18		"github.com/harborworks/booking-hub/internal/repository"
19	)
20	
21	// AuthSettings groups all timing knobs for authentication. They are constants
22	// in the spec, but exposing them as a struct keeps the service testable.
23	type AuthSettings struct {
24		SessionInactivity time.Duration // 30m: time-since-last-activity that ends a session
25		SessionAbsoluteTTL time.Duration // hard upper bound on a session's lifespan
26		LockoutThreshold  int           // 5: failed attempts before lockout
27		LockoutDuration   time.Duration // 15m
28		CaptchaThreshold  int           // 2: failed attempts after which captcha is required
29		CaptchaTTL        time.Duration // 5m
30		BcryptCost        int           // 10–12 typical
31		CookieSecure      bool          // emit Secure flag on session cookies
32	}
33	
34	func DefaultAuthSettings() AuthSettings {
35		return AuthSettings{
36			SessionInactivity:  30 * time.Minute,
37			SessionAbsoluteTTL: 12 * time.Hour,
38			LockoutThreshold:   5,
39			LockoutDuration:    15 * time.Minute,
40			CaptchaThreshold:   2,
41			CaptchaTTL:         5 * time.Minute,
42			BcryptCost:         bcrypt.DefaultCost,
43			CookieSecure:       true,
44		}
45	}
46	
47	type AuthService struct {
48		users    repository.UserRepository
49		sessions repository.SessionRepository
50		captchas repository.CaptchaRepository
51		log      *slog.Logger
52		cfg      AuthSettings
53	}
54	
55	func NewAuthService(
56		users repository.UserRepository,
57		sessions repository.SessionRepository,
58		captchas repository.CaptchaRepository,
59		log *slog.Logger,
60		cfg AuthSettings,
61	) *AuthService {
62		return &AuthService{users: users, sessions: sessions, captchas: captchas, log: log, cfg: cfg}
63	}
64	
65	// Settings exposes the configured timings (read-only).
66	func (s *AuthService) Settings() AuthSettings { return s.cfg }
67	
68	// ---------- registration ----------
69	
70	func (s *AuthService) Register(ctx context.Context, username, password string) (*domain.User, error) {
71		username = strings.TrimSpace(username)
72		if len(username) < 3 || len(username) > 64 {
73			return nil, errors.Join(domain.ErrInvalidInput, errors.New("username must be 3–64 characters"))
74		}
75		if err := domain.ValidatePassword(password); err != nil {
76			return nil, err
77		}
78	
79		if existing, err := s.users.GetByUsername(ctx, username); err == nil && existing != nil {
80			return nil, errors.Join(domain.ErrConflict, errors.New("username is already taken"))
81		} else if err != nil && !errors.Is(err, domain.ErrNotFound) {
82			return nil, err
83		}
84	
85		hash, err := bcrypt.GenerateFromPassword([]byte(password), s.cfg.BcryptCost)
86		if err != nil {
87			return nil, fmt.Errorf("hash password: %w", err)
88		}
89		u := &domain.User{
90			Username:     username,
91			PasswordHash: string(hash),
92		}
93		if err := s.users.Create(ctx, u); err != nil {
94			return nil, err
95		}
96		s.log.Info("user registered", "user_id", u.ID, "username", u.Username)
97		return u, nil
98	}
99	
100	// ---------- login ----------
101	
102	// LoginInput captures everything the login endpoint may receive.
103	type LoginInput struct {
104		Username      string
105		Password      string
106		CaptchaToken  string
107		CaptchaAnswer string
108		UserAgent     string
109		IP            string
110	}
111	
112	// LoginResult is returned on successful authentication.
113	type LoginResult struct {
114		Session *domain.Session
115		User    *domain.User
116	}
117	
118	// Login validates credentials and produces a session. It implements:
119	//   - lockout (5 failed attempts → 15 minute block)
120	//   - CAPTCHA from the 3rd attempt
121	//   - failed-attempt accounting
122	func (s *AuthService) Login(ctx context.Context, in LoginInput) (*LoginResult, error) {
123		now := time.Now().UTC()
124		in.Username = strings.TrimSpace(in.Username)
125	
126		user, err := s.users.GetByUsername(ctx, in.Username)
127		if err != nil {
128			if errors.Is(err, domain.ErrNotFound) {
129				// Constant-time-ish: still consume bcrypt cost on a dummy hash
130				_ = bcrypt.CompareHashAndPassword(
131					[]byte("$2a$10$abcdefghijklmnopqrstuv0123456789ABCDEFGHIJKLMNOPQRSTUV"),
132					[]byte(in.Password),
133				)
134				return nil, domain.ErrCredentialInvalid
135			}
136			return nil, err
137		}
138	
139		if user.IsLocked(now) {
140			return nil, errors.Join(domain.ErrLocked,
141				fmt.Errorf("locked until %s", user.LockedUntil.Format(time.RFC3339)))
142		}
143	
144		// CAPTCHA gate. Required from the 3rd attempt onward.
145		if user.CaptchaRequired() {
146			if in.CaptchaToken == "" || in.CaptchaAnswer == "" {
147				return nil, domain.ErrCaptchaRequired
148			}
149			if err := s.verifyCaptcha(ctx, in.CaptchaToken, in.CaptchaAnswer, now); err != nil {
150				return nil, err
151			}
152		}
153	
154		if err := bcrypt.CompareHashAndPassword([]byte(user.PasswordHash), []byte(in.Password)); err != nil {
155			// Failed credentials: increment counter and (maybe) lock.
156			var lockUntil *time.Time
157			if user.FailedAttempts+1 >= s.cfg.LockoutThreshold {
158				until := now.Add(s.cfg.LockoutDuration)
159				lockUntil = &until
160			}
161			if err := s.users.RecordFailedLogin(ctx, user.ID, lockUntil); err != nil {
162				s.log.Error("record failed login", "error", err, "user_id", user.ID)
163			}
164			s.log.Warn("login failed",
165				"username", in.Username,
166				"failed_attempts_was", user.FailedAttempts,
167				"locked_after", lockUntil != nil)
168			if lockUntil != nil {
169				return nil, errors.Join(domain.ErrLocked,
170					fmt.Errorf("locked until %s", lockUntil.Format(time.RFC3339)))
171			}
172			return nil, domain.ErrCredentialInvalid
173		}
174	
175		// Success: reset counters and create a session.
176		if err := s.users.ResetFailedLogin(ctx, user.ID, now); err != nil {
177			s.log.Error("reset login counter", "error", err, "user_id", user.ID)
178		}
179		user.FailedAttempts = 0
180		user.LockedUntil = nil
181		user.LastLoginAt = &now
182	
183		sessID, err := generateToken(32)
184		if err != nil {
185			return nil, fmt.Errorf("generate session token: %w", err)
186		}
187		sess := &domain.Session{
188			ID:             sessID,
189			UserID:         user.ID,
190			CreatedAt:      now,
191			LastActivityAt: now,
192			ExpiresAt:      now.Add(s.cfg.SessionInactivity),
193			UserAgent:      in.UserAgent,
194			IP:             in.IP,
195		}
196		if err := s.sessions.Create(ctx, sess); err != nil {
197			return nil, err
198		}
199		s.log.Info("login success", "user_id", user.ID, "username", user.Username, "session_id", sess.ID[:8]+"...")
200		return &LoginResult{Session: sess, User: user}, nil
201	}
202	
203	// ResolveSession validates a session token, enforces inactivity timeout, and
204	// slides the expiry forward. Returns the user attached to the session.
205	func (s *AuthService) ResolveSession(ctx context.Context, sessionID string) (*domain.User, *domain.Session, error) {
206		if sessionID == "" {
207			return nil, nil, domain.ErrUnauthorized
208		}
209		sess, err := s.sessions.Get(ctx, sessionID)
210		if err != nil {
211			if errors.Is(err, domain.ErrNotFound) {
212				return nil, nil, domain.ErrUnauthorized
213			}
214			return nil, nil, err
215		}
216		now := time.Now().UTC()
217		if now.After(sess.ExpiresAt) {
218			_ = s.sessions.Delete(ctx, sessionID)
219			return nil, nil, domain.ErrSessionExpired
220		}
221		// Absolute lifetime cap
222		if now.Sub(sess.CreatedAt) > s.cfg.SessionAbsoluteTTL {
223			_ = s.sessions.Delete(ctx, sessionID)
224			return nil, nil, domain.ErrSessionExpired
225		}
226	
227		user, err := s.users.GetByID(ctx, sess.UserID)
228		if err != nil {
229			return nil, nil, err
230		}
231	
232		// Slide the inactivity window forward.
233		newExpires := now.Add(s.cfg.SessionInactivity)
234		if err := s.sessions.Touch(ctx, sess.ID, now, newExpires); err != nil {
235			s.log.Warn("touch session", "error", err)
236		}
237		sess.LastActivityAt = now
238		sess.ExpiresAt = newExpires
239		return user, sess, nil
240	}
241	
242	// ChangePassword validates the current password, the new password against
243	// the policy, and bcrypt-hashes the new value before storing it. The
244	// must_rotate_password flag is cleared as a side effect of UpdatePasswordHash.
245	func (s *AuthService) ChangePassword(ctx context.Context, userID uuid.UUID, current, next string) error {
246		user, err := s.users.GetByID(ctx, userID)
247		if err != nil {
248			return err
249		}
250		if err := bcrypt.CompareHashAndPassword([]byte(user.PasswordHash), []byte(current)); err != nil {
251			return domain.ErrCredentialInvalid
252		}
253		if err := domain.ValidatePassword(next); err != nil {
254			return err
255		}
256		hash, err := bcrypt.GenerateFromPassword([]byte(next), s.cfg.BcryptCost)
257		if err != nil {
258			return fmt.Errorf("hash new password: %w", err)
259		}
260		if err := s.users.UpdatePasswordHash(ctx, userID, string(hash)); err != nil {
261			return err
262		}
263		s.log.Info("password rotated", "user_id", userID)
264		return nil
265	}
266	
267	func (s *AuthService) Logout(ctx context.Context, sessionID string) error {
268		if sessionID == "" {
269			return nil
270		}
271		return s.sessions.Delete(ctx, sessionID)
272	}
273	
274	// ---------- captcha ----------
275	
276	// IssueCaptcha mints a new math challenge "What is X + Y?" and returns the
277	// public token+question. The answer is stored server-side only.
278	func (s *AuthService) IssueCaptcha(ctx context.Context) (*domain.CaptchaChallenge, error) {
279		a, err := randInt(1, 9)
280		if err != nil {
281			return nil, err
282		}
283		b, err := randInt(1, 9)
284		if err != nil {
285			return nil, err
286		}
287		tok, err := generateToken(16)
288		if err != nil {
289			return nil, err
290		}
291		now := time.Now().UTC()
292		c := &domain.CaptchaChallenge{
293			Token:     tok,
294			Question:  fmt.Sprintf("What is %d + %d?", a, b),
295			Answer:    fmt.Sprintf("%d", a+b),
296			CreatedAt: now,
297			ExpiresAt: now.Add(s.cfg.CaptchaTTL),
298		}
299		if err := s.captchas.Create(ctx, c); err != nil {
300			return nil, err
301		}
302		return c, nil
303	}
304	
305	func (s *AuthService) verifyCaptcha(ctx context.Context, token, answer string, now time.Time) error {
306		c, err := s.captchas.Get(ctx, token)
307		if err != nil {
308			if errors.Is(err, domain.ErrNotFound) {
309				return domain.ErrCaptchaInvalid
310			}
311			return err
312		}
313		if c.Consumed || now.After(c.ExpiresAt) {
314			return domain.ErrCaptchaInvalid
315		}
316		if strings.TrimSpace(answer) != c.Answer {
317			// Burn the challenge so it can't be brute-forced.
318			_ = s.captchas.Consume(ctx, token)
319			return domain.ErrCaptchaInvalid
320		}
321		if err := s.captchas.Consume(ctx, token); err != nil {
322			return err
323		}
324		return nil
325	}
326	
327	// ---------- helpers ----------
328	
329	func generateToken(byteLen int) (string, error) {
330		buf := make([]byte, byteLen)
331		if _, err := rand.Read(buf); err != nil {
332			return "", err
333		}
334		return base64.RawURLEncoding.EncodeToString(buf), nil
335	}
336	
337	func randInt(min, max int64) (int64, error) {
338		n, err := rand.Int(rand.Reader, big.NewInt(max-min+1))
339		if err != nil {
340			return 0, err
341		}
342		return n.Int64() + min, nil
343	}
344	
