108	func (r *groupBuyRepo) JoinAtomic(ctx context.Context, gbID, userID uuid.UUID, qty int) (*domain.GroupBuy, *domain.GroupBuyParticipant, error) {
109		if qty <= 0 {
110			qty = 1
111		}
112		tx, err := r.pool.BeginTx(ctx, pgx.TxOptions{IsoLevel: pgx.ReadCommitted})
113		if err != nil {
114			return nil, nil, fmt.Errorf("begin tx: %w", err)
115		}
116		defer func() { _ = tx.Rollback(ctx) }()
117	
118		// Read current state.
119		row := tx.QueryRow(ctx, `SELECT `+groupBuyColumns+` FROM group_buys WHERE id = $1`, gbID)
120		g, err := scanGroupBuy(row)
121		if err != nil {
122			if errors.Is(err, pgx.ErrNoRows) {
123				return nil, nil, domain.ErrNotFound
124			}
125			return nil, nil, err
126		}
127		if g.Status != domain.GroupBuyOpen && g.Status != domain.GroupBuyMet {
128			return nil, nil, errors.Join(domain.ErrConflict, fmt.Errorf("group buy is %s", g.Status))
129		}
130		now := time.Now().UTC()
131		if !g.Deadline.After(now) {
132			return nil, nil, domain.ErrDeadlinePassed
133		}
134		if g.RemainingSlots < qty {
135			return nil, nil, domain.ErrOversold
136		}
137	
138		// Optimistic-locked decrement: only succeeds if version unchanged.
139		const upd = `
