88			Description: in.Description,
89			Threshold:   threshold,
90			Capacity:    in.Capacity,
91			StartsAt:    in.StartsAt.UTC(),
92			EndsAt:      in.EndsAt.UTC(),
93			Deadline:    deadline,
94			Status:      domain.GroupBuyOpen,
95		}
96		if err := g.Validate(now); err != nil {
97			return nil, err
98		}
99		if err := s.repo.Create(ctx, g); err != nil {
100			return nil, err
101		}
