162		g, err := s.repo.Get(ctx, id)
163		if err != nil {
164			return nil, err
165		}
166		now := time.Now().UTC()
167		left := int64(g.Deadline.Sub(now).Seconds())
168		if left < 0 {
169			left = 0
170		}
171		return &Progress{
172			GroupBuyID:     g.ID,
173			Threshold:      g.Threshold,
174			Confirmed:      g.Confirmed(),
175			RemainingSlots: g.RemainingSlots,
176			Capacity:       g.Capacity,
177			Ratio:          g.Progress(),
178			ThresholdMet:   g.ThresholdMet(),
