185	// SweepExpired is a job step: any open or met group buy whose deadline has
186	// passed is moved to a terminal state. Three cases:
187	//
188	//   - threshold met         → finalized
189	//   - threshold NOT met,
190	//     at least one joiner   → failed (slots are released back to the
191	//                             underlying resource so it can be re-used)
192	//   - no participants       → expired
193	//
194	// In every case the organizer is notified. The "failed" path uses a
195	// dedicated repository method that updates the status and resets
196	// remaining_slots = capacity in a single transaction so the invariant
197	// "a non-finalized terminal group buy holds zero pre-allocated seats"
198	// always holds.
199	func (s *GroupBuyService) SweepExpired(ctx context.Context) error {
200		now := time.Now().UTC()
201		expiring, err := s.repo.ListExpiringBefore(ctx, now)
202		if err != nil {
203			return err
204		}
205		for i := range expiring {
206			g := &expiring[i]
207			target := domain.GroupBuyExpired
208			switch {
209			case g.ThresholdMet():
210				target = domain.GroupBuyFinalized
211			case g.Confirmed() > 0:
212				target = domain.GroupBuyFailed
213			}
214	
215			if target == domain.GroupBuyFailed {
216				if err := s.repo.MarkFailedAndReleaseSlots(ctx, g.ID); err != nil {
217					s.log.Warn("sweep release-and-fail failed", "id", g.ID, "error", err)
218					continue
219				}
220			} else {
221				if err := s.repo.UpdateStatus(ctx, g.ID, target); err != nil {
222					s.log.Warn("sweep update failed", "id", g.ID, "error", err)
223					continue
224				}
225			}
226	
227			_ = s.notifications.CreateNotification(ctx, &domain.Notification{
228				UserID: g.OrganizerID,
229				Kind:   "group_buy_" + string(target),
230				Title:  fmt.Sprintf("Group buy %q %s", g.Title, target),
231				Body:   fmt.Sprintf("%d / %d confirmed at deadline.", g.Confirmed(), g.Threshold),
232			})
233		}
234		return nil
235	}
