238		if !g.ThresholdMet() {
239			return
240		}
241		if g.Status != domain.GroupBuyMet {
242			return
243		}
244		_ = s.notifications.CreateNotification(ctx, &domain.Notification{
245			UserID: g.OrganizerID,
246			Kind:   "group_buy_threshold_met",
247			Title:  fmt.Sprintf("Group buy %q reached its threshold", g.Title),
248			Body:   fmt.Sprintf("%d / %d seats confirmed.", g.Confirmed(), g.Threshold),
249		})
250	}
