1	package unit_tests
2	
3	import (
4		"errors"
5		"testing"
6		"time"
7	
8		"github.com/google/uuid"
9	
10		"github.com/harborworks/booking-hub/internal/domain"
11	)
12	
13	func makeGoodGroupBuy(now time.Time) *domain.GroupBuy {
14		return &domain.GroupBuy{
15			ID:             uuid.New(),
16			ResourceID:     uuid.New(),
17			OrganizerID:    uuid.New(),
18			Title:          "Sunset cruise",
19			Threshold:      5,
20			Capacity:       10,
21			RemainingSlots: 10,
22			StartsAt:       now.Add(2 * time.Hour),
23			EndsAt:         now.Add(4 * time.Hour),
24			Deadline:       now.Add(time.Hour),
25			Status:         domain.GroupBuyOpen,
26		}
27	}
28	
29	func TestGroupBuyConfirmedAndProgress(t *testing.T) {
30		now := time.Now().UTC()
31		g := makeGoodGroupBuy(now)
32		if g.Confirmed() != 0 {
33			t.Fatalf("confirmed should be 0")
34		}
35		if g.ThresholdMet() {
36			t.Fatal("not met yet")
37		}
38		if g.Progress() != 0 {
39			t.Fatalf("progress = %v", g.Progress())
40		}
41	
42		g.RemainingSlots = 7 // 3 confirmed
43		if g.Confirmed() != 3 {
44			t.Fatalf("confirmed = %d", g.Confirmed())
45		}
46		if got := g.Progress(); got <= 0.59 || got >= 0.61 {
47			t.Fatalf("progress ≈ 0.6, got %v", got)
48		}
49	
50		g.RemainingSlots = 3 // 7 confirmed > threshold (5)
51		if !g.ThresholdMet() {
52			t.Fatal("should be met")
53		}
54		if g.Progress() != 1.0 {
55			t.Fatalf("capped at 1.0, got %v", g.Progress())
56		}
57	
58		// Edge: zero threshold returns 0 (avoids divide-by-zero).
59		g.Threshold = 0
60		if g.Progress() != 0 {
61			t.Fatalf("zero threshold → 0, got %v", g.Progress())
62		}
63	}
64	
65	func TestGroupBuyValidate(t *testing.T) {
66		now := time.Now().UTC()
67		g := makeGoodGroupBuy(now)
68		if err := g.Validate(now); err != nil {
69			t.Fatalf("good: %v", err)
70		}
71	
72		cases := []struct {
73			name string
74			mut  func(g *domain.GroupBuy)
75		}{
76			{"missing title", func(g *domain.GroupBuy) { g.Title = "" }},
77			{"non-positive threshold", func(g *domain.GroupBuy) { g.Threshold = 0 }},
78			{"non-positive capacity", func(g *domain.GroupBuy) { g.Capacity = 0 }},
79			{"threshold > capacity", func(g *domain.GroupBuy) { g.Threshold = 100 }},
80			{"end before start", func(g *domain.GroupBuy) { g.EndsAt = g.StartsAt }},
81			{"deadline in past", func(g *domain.GroupBuy) { g.Deadline = now.Add(-time.Minute) }},
82			{"deadline after start", func(g *domain.GroupBuy) { g.Deadline = g.StartsAt.Add(time.Hour) }},
83		}
84		for _, c := range cases {
85			t.Run(c.name, func(t *testing.T) {
86				gg := *makeGoodGroupBuy(now)
87				c.mut(&gg)
88				err := gg.Validate(now)
89				if err == nil {
90					t.Fatal("expected error")
91				}
92				if !errors.Is(err, domain.ErrInvalidInput) {
93					t.Errorf("expected ErrInvalidInput, got %v", err)
94				}
95			})
96		}
97	}
98	
