1	package views
2	
3	import (
4		"fmt"
5		"time"
6	
7		"github.com/harborworks/booking-hub/internal/domain"
8	)
9	
10	func formatDateTime(t time.Time) string {
11		return t.UTC().Format("2006-01-02 15:04 UTC")
12	}
13	
14	func nextHourISO() string {
15		t := time.Now().UTC().Add(3 * time.Hour).Truncate(time.Hour)
16		return t.Format("2006-01-02T15:04")
17	}
18	
19	func nextHourPlusISO() string {
20		t := time.Now().UTC().Add(4 * time.Hour).Truncate(time.Hour)
21		return t.Format("2006-01-02T15:04")
22	}
23	
24	templ MyBookingsPage(username string, blacklisted bool, blReason string, bookings []domain.Booking) {
25		@Layout("My Bookings", username) {
26			<h2>My bookings</h2>
27			if blacklisted {
28				<div class="error">
29					<strong>Account is blacklisted.</strong> New booking requests are blocked.
30					if blReason != "" {
31						<br/>Reason: { blReason }
32					}
33				</div>
34			}
35			if len(bookings) == 0 {
36				<div class="empty">
37					No bookings yet. <a href="/bookings/new">Create one</a>.
38				</div>
39			} else {
40				<table>
41					<thead>
42						<tr>
43							<th>Resource</th>
44							<th>Start</th>
45							<th>End</th>
46							<th>Party</th>
47							<th>Status</th>
48							<th>Actions</th>
49						</tr>
50					</thead>
51					<tbody>
52						for _, b := range bookings {
53							<tr>
54								<td><code>{ b.ResourceID.String()[:8] }…</code></td>
55								<td>{ formatDateTime(b.StartTime) }</td>
56								<td>{ formatDateTime(b.EndTime) }</td>
57								<td>{ fmt.Sprintf("%d", b.PartySize) }</td>
58								<td><span class={ "badge", string(b.Status) }>{ string(b.Status) }</span></td>
59								<td class="actions">
60									if !b.Status.IsTerminal() {
61										for _, next := range domain.AllowedNext(b.Status) {
62											<button class="btn-inline" onclick={ transitionScript(b.ID.String(), string(next)) }>{ string(next) }</button>
63										}
64									}
65								</td>
66							</tr>
67						}
68					</tbody>
69				</table>
70				<script>
71					function harborTransition(id, target) {
72						fetch('/api/bookings/' + id + '/transition', {
73							method: 'POST',
74							headers: { 'Content-Type': 'application/json' },
75							body: JSON.stringify({ target_state: target }),
76						}).then(async (res) => {
77							if (res.ok) { location.reload(); return; }
78							const data = await res.json().catch(() => ({}));
79							alert('Transition failed: ' + (data.error || res.statusText));
80						});
81					}
82				</script>
83			}
84		}
85	}
86	
87	script transitionScript(id, target string) {
88		harborTransition(id, target);
89	}
90	
91	templ NewBookingPage(username string, resources []domain.Resource, errMsg string) {
92		@Layout("New Booking", username) {
93			<h2>New booking</h2>
94			if errMsg != "" {
95				<div class="error">{ errMsg }</div>
96			}
97			<div class="card" style="max-width:560px;">
98				<form class="stacked" id="newBookingForm">
99					<label>
100						Resource
101						<select name="resource_id" required>
102							for _, r := range resources {
103								<option value={ r.ID.String() }>{ r.Name } — { r.Description }</option>
104							}
105						</select>
106					</label>
107					<label>
108						Start time (UTC)
109						<input type="datetime-local" name="start_time" value={ nextHourISO() } required/>
110					</label>
111					<label>
112						End time (UTC)
113						<input type="datetime-local" name="end_time" value={ nextHourPlusISO() } required/>
114					</label>
115					<label>
116						Party size
117						<input type="number" name="party_size" min="1" value="1" required/>
118					</label>
119					<label>
120						Notes
121						<textarea name="notes" rows="2"></textarea>
122					</label>
123					<button type="submit">Create booking</button>
124				</form>
125				<p class="muted" style="margin-top:1rem;">
126					Bookings need at least 2 hours lead time. Resource conflicts are
127					automatically waitlisted.
128				</p>
129			</div>
130			<script>
131				document.getElementById('newBookingForm').addEventListener('submit', async (e) => {
132					e.preventDefault();
133					const fd = new FormData(e.target);
134					const body = Object.fromEntries(fd.entries());
135					body.party_size = parseInt(body.party_size, 10);
136					const res = await fetch('/api/bookings', {
137						method: 'POST',
138						headers: { 'Content-Type': 'application/json' },
139						body: JSON.stringify(body),
140					});
141					if (res.ok) { window.location.href = '/'; return; }
142					const data = await res.json().catch(() => ({}));
143					alert('Booking failed: ' + (data.error || res.statusText));
144				});
145			</script>
146		}
147	}
