19	// BackupService writes JSON exports to a local "removable media" directory
20	// (mounted via docker volume). Daily incrementals only export rows whose
21	// updated_at column changed since the last successful backup; weekly fulls
22	// dump every table. Restore reads the latest full + every incremental newer
23	// than that full. The 4-hour SLA is honored simply by being O(rows).
24	type BackupService struct {
25		pool   *pgxpool.Pool
26		repo   repository.BackupRepository
27		target string
28		log    *slog.Logger
29	}
30	
31	func NewBackupService(pool *pgxpool.Pool, repo repository.BackupRepository, targetDir string, log *slog.Logger) *BackupService {
32		return &BackupService{pool: pool, repo: repo, target: targetDir, log: log}
33	}
34	
35	// Tables that participate in backup/restore. Order matters for restore so
36	// foreign keys resolve cleanly.
37	var backupTables = []string{
38		"resources",
39		"group_reservations",
40		"users",
41		"bookings",
42		"group_buys",
43		"group_buy_participants",
44		"documents",
45		"document_revisions",
46		"notifications",
47		"todos",
48		"notification_deliveries",
49		"data_dictionary",
50		"tags",
51		"taggings",
52		"consent_records",
53		"webhooks",
54		"webhook_deliveries",
55		"analytics_events",
56		"analytics_hourly",
57		"anomaly_alerts",
58	}
59	
60	// TakeFull writes a full snapshot of all backupTables.
61	func (s *BackupService) TakeFull(ctx context.Context) (*domain.Backup, error) {
62		return s.take(ctx, "full", time.Time{})
63	}
64	
65	// TakeIncremental writes only rows whose updated_at is newer than the
66	// previous successful backup. The baseline is the most recent backup of
67	// either kind (full OR incremental) — using the last full snapshot as
68	// the baseline would re-emit every row that already shipped in earlier
69	// incrementals between fulls. Falls back to "no since" (full export) if
70	// the table is empty so the very first incremental still produces a
71	// usable file.
72	func (s *BackupService) TakeIncremental(ctx context.Context) (*domain.Backup, error) {
73		last, err := s.repo.LastSuccessful(ctx)
74		since := time.Time{}
75		if err == nil && last != nil {
76			since = last.TakenAt
77		}
78		return s.take(ctx, "incremental", since)
79	}
80	
81	func (s *BackupService) take(ctx context.Context, kind string, since time.Time) (*domain.Backup, error) {
82		if err := os.MkdirAll(s.target, 0o755); err != nil {
83			return nil, fmt.Errorf("ensure backup dir: %w", err)
84		}
85		now := time.Now().UTC()
86		name := fmt.Sprintf("harborworks-%s-%s.json", kind, now.Format("20060102T150405Z"))
87		path := filepath.Join(s.target, name)
88	
89		dump := map[string][]map[string]any{}
90		for _, table := range backupTables {
91			rows, err := s.dumpTable(ctx, table, since)
92			if err != nil {
93				s.log.Warn("table dump failed", "table", table, "error", err)
94				continue
95			}
96			dump[table] = rows
97		}
98		body, err := json.MarshalIndent(map[string]any{
99			"kind":       kind,
100			"taken_at":   now,
101			"since":      since,
102			"row_counts": rowCounts(dump),
103			"tables":     dump,
104		}, "", "  ")
105		if err != nil {
106			return nil, err
107		}
108		if err := os.WriteFile(path, body, 0o600); err != nil {
109			return nil, err
110		}
111		b := &domain.Backup{
112			Kind:      kind,
113			Path:      path,
114			SizeBytes: int64(len(body)),
115			TakenAt:   now,
116			Detail:    fmt.Sprintf("tables=%d", len(dump)),
117		}
118		if err := s.repo.Insert(ctx, b); err != nil {
119			return nil, err
120		}
121		s.log.Info("backup written", "kind", kind, "path", path, "bytes", len(body))
122		return b, nil
123	}
124	
125	// dumpTable selects all rows from the given table; if the table has an
126	// updated_at column and `since` is non-zero, only newer rows are returned.
127	func (s *BackupService) dumpTable(ctx context.Context, table string, since time.Time) ([]map[string]any, error) {
128		q := "SELECT row_to_json(t) FROM " + table + " t"
129		args := []any{}
130		if !since.IsZero() && tableHasUpdatedAt(table) {
131			q += " WHERE updated_at > $1"
132			args = append(args, since)
133		}
134		rows, err := s.pool.Query(ctx, q, args...)
135		if err != nil {
136			return nil, err
137		}
138		defer rows.Close()
139		out := make([]map[string]any, 0, 64)
140		for rows.Next() {
141			var raw []byte
142			if err := rows.Scan(&raw); err != nil {
143				return nil, err
144			}
145			var m map[string]any
146			if err := json.Unmarshal(raw, &m); err != nil {
147				return nil, err
148			}
149			out = append(out, m)
150		}
151		return out, rows.Err()
152	}
153	
154	func tableHasUpdatedAt(table string) bool {
155		switch table {
156		case "users", "bookings", "group_reservations", "group_buys", "documents", "todos":
157			return true
158		}
159		return false
160	}
161	
162	func rowCounts(dump map[string][]map[string]any) map[string]int {
163		out := map[string]int{}
164		for k, v := range dump {
165			out[k] = len(v)
166		}
167		return out
168	}
169	
170	// List returns the backup index for admin pages.
171	func (s *BackupService) List(ctx context.Context, limit int) ([]domain.Backup, error) {
172		return s.repo.List(ctx, limit)
173	}
174	
175	// PlanRestore returns the chain of files needed to restore to "now": the
176	// most recent full plus every incremental written after it. The caller can
177	// inspect this list before invoking ApplyRestore.
178	func (s *BackupService) PlanRestore(ctx context.Context) ([]domain.Backup, error) {
179		full, err := s.repo.LastFull(ctx)
180		if err != nil {
181			return nil, errors.New("no full backup available")
182		}
183		incrementals, err := s.repo.IncrementalsAfter(ctx, full.TakenAt)
184		if err != nil {
185			return nil, err
186		}
187		plan := []domain.Backup{*full}
188		plan = append(plan, incrementals...)
189		return plan, nil
190	}
