120	// RunDeletionExecutor is the background-job step that processes every
121	// deletion request whose 7-day grace window has elapsed. For each request:
122	//
123	//  1. Analytics events are detached: the per-user salted hash is set to NULL
124	//     so the rows survive as anonymized aggregates with no link back.
125	//  2. The user row is hard-deleted. Migration 0003 makes every dependent
126	//     FK either CASCADE (sessions, bookings, documents/revisions, todos,
127	//     notifications, consent_records, group_buy_participants, deletion_
128	//     requests) or SET NULL (group_buys.organizer_id), so a single DELETE
129	//     removes every personal-data row in one transaction.
130	//
131	// The deletion is logged with the user id only (no PII).
132	func (s *GovernanceService) RunDeletionExecutor(ctx context.Context) error {
133		now := time.Now().UTC()
134		due, err := s.repo.ListDuePending(ctx, now)
135		if err != nil {
136			return err
137		}
138		for _, d := range due {
139			if err := s.hardDeleteOne(ctx, d); err != nil {
140				s.log.Warn("deletion executor failed", "user_id", d.UserID, "error", err)
141			}
142		}
143		return nil
144	}
145	
146	func (s *GovernanceService) hardDeleteOne(ctx context.Context, d domain.DeletionRequest) error {
147		// 1. Detach analytics first (uses the salted hash, not the user_id, so
148		//    it must run before the user row is gone).
149		if err := s.analytics.AnonymiseUserEvents(ctx, d.UserID); err != nil {
150			return fmt.Errorf("anonymise analytics: %w", err)
151		}
152		// 2. Hard delete. Cascades + SET NULL handle every dependent table.
153		if err := s.users.HardDelete(ctx, d.UserID); err != nil {
154			return fmt.Errorf("hard delete user: %w", err)
155		}
156		// 3. The deletion_requests row is gone via cascade — log the event so
157		//    auditors can correlate. Only the user id (a UUID) appears here.
158		s.log.Info("user hard-deleted", "user_id", d.UserID, "request_id", d.ID)
159		return nil
160	}
