164	// CSVValidationError describes one row that failed bulk validation.
165	type CSVValidationError struct {
166		Row    int    `json:"row"`
167		Field  string `json:"field"`
168		Reason string `json:"reason"`
169	}
170	
171	// ParsedResourceRow is one row that survived bulk validation. Exported so
172	// unit tests can assert on the parsed form without round-tripping through DB.
173	type ParsedResourceRow struct {
174		Name        string
175		Description string
176		Capacity    int
177	}
178	
179	// isDateLikeColumn reports whether a header name is conventionally typed
180	// as a date/time. The CSV importer rejects any value in such columns that
181	// is not a strictly-parseable RFC3339 timestamp or YYYY-MM-DD calendar
182	// date. This catches the common operator mistake of pasting an Excel
183	// "general" cell ("4/8/2026", "Apr 8 2026", "1744070400") into what
184	// should be an ISO timestamp column.
185	func isDateLikeColumn(name string) bool {
186		n := strings.ToLower(strings.TrimSpace(name))
187		if n == "" {
188			return false
189		}
190		if n == "date" || strings.HasSuffix(n, "_at") || strings.HasSuffix(n, "_date") ||
191			strings.HasSuffix(n, "_time") || strings.HasPrefix(n, "date_") {
192			return true
193		}
194		return false
195	}
196	
197	// validateDateField returns "" if value parses as either RFC3339 / RFC3339Nano
198	// or as a bare YYYY-MM-DD calendar date. Otherwise it returns a human-readable
199	// reason.
200	func validateDateField(value string) string {
201		v := strings.TrimSpace(value)
202		if v == "" {
203			return "required (RFC3339 or YYYY-MM-DD)"
204		}
205		for _, layout := range []string{time.RFC3339Nano, time.RFC3339, "2006-01-02"} {
206			if _, err := time.Parse(layout, v); err == nil {
207				return ""
208			}
209		}
210		return "must be RFC3339 or YYYY-MM-DD; got " + strconv.Quote(v)
211	}
