213	// ValidateResourcesCSV is a pure function that performs all schema and row
214	// checks for a resource CSV import. It is intentionally side-effect free so
215	// unit tests can exercise every branch without a database. The contract is
216	// "all-or-nothing": when any row fails, the slice of validation errors is
217	// returned and `parsed` is empty.
218	func ValidateResourcesCSV(body io.Reader) (parsed []ParsedResourceRow, errs []CSVValidationError, fatal error) {
219		r := csv.NewReader(body)
220		r.TrimLeadingSpace = true
221		rows, err := r.ReadAll()
222		if err != nil {
223			return nil, nil, fmt.Errorf("parse csv: %w", err)
224		}
225		if len(rows) == 0 {
226			return nil, nil, errors.New("csv is empty")
227		}
228		header := rows[0]
229		colIdx := map[string]int{}
230		for i, h := range header {
231			colIdx[strings.ToLower(strings.TrimSpace(h))] = i
232		}
233		required := []string{"name", "description", "capacity"}
234		for _, c := range required {
235			if _, ok := colIdx[c]; !ok {
236				return nil, nil, fmt.Errorf("missing column %q", c)
237			}
238		}
239	
240		// Pre-compute which columns must satisfy the strict date format. This
241		// covers any optional column the operator added (e.g. effective_at,
242		// retire_date) on top of the required name/description/capacity set.
243		dateCols := map[string]int{}
244		for h, idx := range colIdx {
245			if isDateLikeColumn(h) {
246				dateCols[h] = idx
247			}
248		}
249	
250		parsed = make([]ParsedResourceRow, 0, len(rows)-1)
251		seen := map[string]bool{}
252		for i := 1; i < len(rows); i++ {
253			row := rows[i]
254			if len(row) < len(header) {
255				errs = append(errs, CSVValidationError{Row: i + 1, Field: "*", Reason: "short row"})
256				continue
257			}
258			name := strings.TrimSpace(row[colIdx["name"]])
259			desc := strings.TrimSpace(row[colIdx["description"]])
260			capStr := strings.TrimSpace(row[colIdx["capacity"]])
261	
262			if name == "" {
263				errs = append(errs, CSVValidationError{Row: i + 1, Field: "name", Reason: "required"})
264				continue
265			}
266			if seen[strings.ToLower(name)] {
267				errs = append(errs, CSVValidationError{Row: i + 1, Field: "name", Reason: "duplicate within file"})
268				continue
269			}
270			seen[strings.ToLower(name)] = true
271	
272			capVal, err := strconv.Atoi(capStr)
273			if err != nil || capVal <= 0 {
274				errs = append(errs, CSVValidationError{Row: i + 1, Field: "capacity", Reason: "must be a positive integer"})
275				continue
276			}
277	
278			// Strict date validation: every column whose header looks like a
279			// timestamp/date must be a parseable RFC3339 value or a bare
280			// YYYY-MM-DD. Any other content is a hard reject — including
281			// empty strings, "TBD", numeric epochs, and locale-specific
282			// formats. This is a deliberate "strict-by-default" policy.
283			dateOK := true
284			for h, idx := range dateCols {
285				if reason := validateDateField(row[idx]); reason != "" {
286					errs = append(errs, CSVValidationError{Row: i + 1, Field: h, Reason: reason})
287					dateOK = false
288				}
289			}
290			if !dateOK {
291				continue
292			}
293	
294			parsed = append(parsed, ParsedResourceRow{Name: name, Description: desc, Capacity: capVal})
295		}
296	
297		if len(errs) > 0 {
298			return nil, errs, nil
299		}
300		return parsed, nil, nil
301	}
