303	// ImportResourcesCSV parses a CSV with the columns name,description,capacity,
304	// validates every row, and persists the surviving rows inside a single
305	// transaction. Any validation error or insert error rolls back the whole
306	// transaction; the returned `inserted` count is the number of rows actually
307	// committed (always 0 on the failure paths).
308	func (s *GovernanceService) ImportResourcesCSV(ctx context.Context, body io.Reader) (inserted int, errs []CSVValidationError, fatal error) {
309		parsed, validationErrs, fatal := ValidateResourcesCSV(body)
310		if fatal != nil {
311			return 0, nil, fatal
