323			})
324		}
325	
326		// All-or-nothing transactional insert. If a row collides with an existing
327		// resource (unique name), the whole transaction is rolled back and the
328		// caller learns about it via fatal.
329		n, err := s.resources.InsertManyTx(ctx, rows)
330		if err != nil {
331			s.log.Warn("csv import rolled back", "error", err)
332			return 0, nil, fmt.Errorf("import rolled back: %w", err)
333		}
334		s.log.Info("csv import committed", "rows", n)
335		return n, nil, nil
336	}
